import "./notificationList.css";
import { NavLink } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { getNotifications, updatedNotification } from "../../redux/apiCalls";
import { useEffect } from "react";
import {format} from 'timeago.js';
import { useTranslation } from 'react-i18next';


const NotificationList = () => {
    const dispatch = useDispatch();
    const notifications = useSelector(state => state.notification.notifications);
    const { t } = useTranslation(["notificationList"]);

    useEffect(() => {
        getNotifications(dispatch)
    }, [dispatch, notifications]);

    const handleToggleRead = (notification) => {
        const notificationToUpdate = {
            ...notification,
            read: !notification.read
        }
        updatedNotification(notification._id, notificationToUpdate, dispatch);
    };

  return (
    <div className='notificationsContainer'>
        <h1 className="notificationsTitle">{t("title")}</h1>
        {notifications.map(notification => {
            return (
                <div className="notificationBlock" key={notification._id}>
                    <button className={notification.read ? "markRead" : "markNotRead"} onClick={() => handleToggleRead(notification)}></button>
                    <div className={notification.read ? "notificationDetails read" : "notificationDetails notRead"} onClick={() => handleToggleRead(notification)}>
                        <div className="topLineList">
                           <b>{t("receivedFromUsername")}</b>: {notification.username}
                        </div>
                        <div className="middleLine">
                            <div className="emailLine"><b>{t("email")}</b>: {notification.email}</div>
                        </div>
                        <div className="middleLine">
                            <div className="subjectLine"><b>{t("subject")}</b>: {notification.subject}</div>
                        </div>
                        <div className="messageBlock">
                            <div className="messageLine">{notification.message.substring(0,100)}...</div>
                        </div>
                        <div className="bottomLine">
                            ({format(notification.createdAt)})
                        </div>
                    </div>
                    <NavLink to={`/notification/${notification._id}`} className="viewLink">
                        {t("viewNotification")}
                    </NavLink>
                </div>
            )
        })}
    </div>
  )
}

export default NotificationList
